+        // For Add body: d(carry)/d(init) = 1.0, d(carry)/d(step) = num_iters = 4
+        let init = Value::scalar_f64(0.0);
+        let step = Value::scalar_f64(3.0);
+        let threshold = Value::scalar_f64(10.0);
+        let g = Value::scalar_f64(1.0);
+        let grads = vjp(
