+        // d(carry)/d(step) = sum over iterations of (carry_final / step_at_each)
+        let init = Value::scalar_f64(1.0);
+        let step = Value::scalar_f64(2.0);
+        let threshold = Value::scalar_f64(100.0);
+        let g = Value::scalar_f64(1.0);
